function render(t, c) {
  const { ctx, width: w, height: h, progress: p } = c;
  const ease = 1 - Math.pow(1 - p, 3);
  ctx.fillStyle = '#05070b';
  ctx.fillRect(0, 0, w, h);
  const cx = w / 2;
  const cy = h / 2;
  for (let ring = 0; ring < 7; ring++) {
    const rr = 70 + ring * 54 + Math.sin(t * 0.9 + ring) * 9;
    ctx.strokeStyle = ring % 2 ? 'rgba(121,217,255,.34)' : 'rgba(123,216,143,.28)';
    ctx.lineWidth = 1 + ring * 0.35;
    ctx.beginPath();
    for (let i = 0; i <= 220; i++) {
      const a = i / 220 * Math.PI * 2;
      const wave = Math.sin(a * 5 + t * 1.8 + ring) * (8 + ring * 2);
      const x = cx + Math.cos(a) * (rr + wave) * (0.98 + ease * 0.02);
      const y = cy + Math.sin(a) * (rr + wave) * 0.48;
      if (i === 0) ctx.moveTo(x, y); else ctx.lineTo(x, y);
    }
    ctx.closePath();
    ctx.stroke();
  }
  for (let i = 0; i < 72; i++) {
    const a = i / 72 * Math.PI * 2 + t * 0.18;
    const r = 240 + Math.sin(i * 1.7 + t) * 42;
    const x = cx + Math.cos(a) * r;
    const y = cy + Math.sin(a) * r * 0.5;
    ctx.fillStyle = i % 3 === 0 ? '#79d9ff' : i % 3 === 1 ? '#7bd88f' : '#ff5c8a';
    ctx.globalAlpha = 0.12 + ease * 0.55;
    ctx.beginPath();
    ctx.arc(x, y, 2 + (i % 5), 0, Math.PI * 2);
    ctx.fill();
  }
  ctx.globalAlpha = 1;
  ctx.textAlign = 'center';
  ctx.textBaseline = 'middle';
  ctx.fillStyle = '#f7f1df';
  ctx.font = '800 78px Arial, sans-serif';
  ctx.fillText('UIV Runtime Core', cx, cy - 24 + (1 - ease) * 36);
  ctx.fillStyle = '#9fb6c9';
  ctx.font = '24px Arial, sans-serif';
  ctx.fillText('one minute, ten segments, one deterministic timeline', cx, cy + 48);
}

function render(t, c) {
  const { ctx, width: w, height: h, progress: p } = c;
  ctx.fillStyle = '#081018';
  ctx.fillRect(0, 0, w, h);
  const nodes = [
    ['root', 640, 128, '#f7f1df'], ['layout', 360, 268, '#79d9ff'], ['motion', 640, 290, '#f2aa4c'], ['media', 920, 268, '#7bd88f'],
    ['text', 260, 454, '#ff5c8a'], ['charts', 470, 500, '#c7a6ff'], ['camera', 640, 500, '#79d9ff'], ['physics', 810, 500, '#7bd88f'], ['export', 1020, 454, '#f2aa4c']
  ];
  const edges = [[0,1],[0,2],[0,3],[1,4],[1,5],[2,6],[3,7],[3,8],[2,7],[5,8]];
  ctx.lineCap = 'round';
  for (const e of edges) {
    const a = nodes[e[0]], b = nodes[e[1]];
    const reveal = Math.min(1, Math.max(0, p * 2.2 - e[0] * 0.08));
    ctx.strokeStyle = 'rgba(223,233,245,.22)';
    ctx.lineWidth = 3;
    ctx.beginPath();
    ctx.moveTo(a[1], a[2]);
    ctx.lineTo(a[1] + (b[1] - a[1]) * reveal, a[2] + (b[2] - a[2]) * reveal);
    ctx.stroke();
  }
  ctx.textAlign = 'center';
  ctx.textBaseline = 'middle';
  nodes.forEach((n, i) => {
    const reveal = Math.min(1, Math.max(0, p * 2.4 - i * 0.08));
    const pulse = 1 + Math.sin(t * 2 + i) * 0.025;
    ctx.globalAlpha = reveal;
    ctx.fillStyle = n[3];
    ctx.beginPath();
    ctx.roundRect(n[1] - 70 * pulse, n[2] - 28 * pulse, 140 * pulse, 56 * pulse, 12);
    ctx.fill();
    ctx.fillStyle = '#061014';
    ctx.font = '700 20px Arial, sans-serif';
    ctx.fillText(n[0], n[1], n[2] + 1);
  });
  ctx.globalAlpha = 1;
  ctx.fillStyle = '#f7f1df';
  ctx.font = '800 46px Arial, sans-serif';
  ctx.fillText('Scene Graph Engine', w / 2, 60);
}

function render(t, c) {
  const { ctx, width: w, height: h, progress: p } = c;
  ctx.fillStyle = '#0a0d13';
  ctx.fillRect(0, 0, w, h);
  const left = 90, right = w - 90, top = 148, laneH = 58;
  const lanes = ['intro', 'graph', 'timeline', 'data', 'physics', '3d', 'export'];
  ctx.font = '700 18px Arial, sans-serif';
  ctx.textAlign = 'right';
  lanes.forEach((lane, i) => {
    const y = top + i * laneH;
    ctx.fillStyle = '#8da1b3';
    ctx.fillText(lane, left - 18, y + 20);
    ctx.strokeStyle = 'rgba(255,255,255,.08)';
    ctx.beginPath();
    ctx.moveTo(left, y + 22);
    ctx.lineTo(right, y + 22);
    ctx.stroke();
  });
  const colors = ['#79d9ff', '#f2aa4c', '#7bd88f', '#ff5c8a', '#c7a6ff'];
  for (let i = 0; i < 28; i++) {
    const lane = i % lanes.length;
    const start = (i * 0.037 + lane * 0.031) % 0.82;
    const len = 0.08 + (i % 5) * 0.028;
    const reveal = Math.min(1, Math.max(0, p * 1.5 - start));
    const x = left + (right - left) * start;
    const y = top + lane * laneH + 4;
    ctx.globalAlpha = 0.25 + reveal * 0.75;
    ctx.fillStyle = colors[i % colors.length];
    ctx.beginPath();
    ctx.roundRect(x, y, (right - left) * len * reveal, 36, 7);
    ctx.fill();
  }
  ctx.globalAlpha = 1;
  const playX = left + (right - left) * p;
  ctx.strokeStyle = '#f7f1df';
  ctx.lineWidth = 3;
  ctx.beginPath();
  ctx.moveTo(playX, 112);
  ctx.lineTo(playX, h - 90);
  ctx.stroke();
  ctx.textAlign = 'center';
  ctx.fillStyle = '#f7f1df';
  ctx.font = '800 44px Arial, sans-serif';
  ctx.fillText('Timeline Engine', w / 2, 62);
  ctx.font = '22px Arial, sans-serif';
  ctx.fillStyle = '#9fb6c9';
  ctx.fillText('frame-accurate segment sampling at 30 fps', w / 2, h - 48);
}

function render(t, c) {
  const { ctx, width: w, height: h, progress: p } = c;
  ctx.fillStyle = '#080b11';
  ctx.fillRect(0, 0, w, h);
  const base = h - 130;
  const left = 120;
  const bw = 40;
  ctx.strokeStyle = 'rgba(255,255,255,.12)';
  ctx.lineWidth = 1;
  for (let y = 0; y < 5; y++) {
    ctx.beginPath();
    ctx.moveTo(left, base - y * 84);
    ctx.lineTo(w - 120, base - y * 84);
    ctx.stroke();
  }
  for (let i = 0; i < 18; i++) {
    const value = 0.24 + Math.abs(Math.sin(i * 0.7 + t * 0.55)) * 0.72;
    const reveal = Math.min(1, Math.max(0, p * 2 - i * 0.045));
    const barH = value * 360 * reveal;
    const x = left + i * 58;
    const grad = ctx.createLinearGradient(0, base - barH, 0, base);
    grad.addColorStop(0, i % 3 === 0 ? '#ff5c8a' : i % 3 === 1 ? '#79d9ff' : '#7bd88f');
    grad.addColorStop(1, 'rgba(255,255,255,.08)');
    ctx.fillStyle = grad;
    ctx.beginPath();
    ctx.roundRect(x, base - barH, bw, barH, 8);
    ctx.fill();
  }
  ctx.strokeStyle = '#f2aa4c';
  ctx.lineWidth = 4;
  ctx.beginPath();
  for (let i = 0; i < 180; i++) {
    const q = i / 179;
    const x = left + q * (w - 240);
    const y = base - 190 - Math.sin(q * Math.PI * 4 + t * 1.2) * 78 - Math.cos(q * Math.PI * 9 + t) * 22;
    if (i === 0) ctx.moveTo(x, y); else ctx.lineTo(x, y);
  }
  ctx.stroke();
  ctx.textAlign = 'center';
  ctx.fillStyle = '#f7f1df';
  ctx.font = '800 46px Arial, sans-serif';
  ctx.fillText('Data-Driven UI Video', w / 2, 64);
  ctx.fillStyle = '#9fb6c9';
  ctx.font = '22px Arial, sans-serif';
  ctx.fillText('D3-style calculation, canvas-first deterministic frames', w / 2, 104);
}

function render(t, c) {
  const { ctx, width: w, height: h, progress: p } = c;
  ctx.fillStyle = '#0b0811';
  ctx.fillRect(0, 0, w, h);
  const floor = h - 112;
  ctx.strokeStyle = 'rgba(247,241,223,.22)';
  ctx.lineWidth = 3;
  ctx.beginPath();
  ctx.moveTo(96, floor);
  ctx.lineTo(w - 96, floor);
  ctx.stroke();
  for (let i = 0; i < 42; i++) {
    const seed = i * 12.989;
    const x = 120 + ((i * 97) % 1040);
    const drop = Math.min(1, Math.max(0, p * 1.6 - (i % 9) * 0.07));
    const bounce = Math.abs(Math.sin(t * 2.1 + seed)) * (1 - drop) * 110;
    const y = 110 + drop * (floor - 150) - bounce + Math.sin(t + i) * 8;
    const size = 16 + (i % 5) * 5;
    ctx.fillStyle = i % 4 === 0 ? '#c7a6ff' : i % 4 === 1 ? '#79d9ff' : i % 4 === 2 ? '#7bd88f' : '#ff5c8a';
    ctx.globalAlpha = 0.35 + drop * 0.65;
    ctx.save();
    ctx.translate(x, y);
    ctx.rotate(t * 0.7 + i);
    ctx.beginPath();
    ctx.roundRect(-size, -size, size * 2, size * 2, 6);
    ctx.fill();
    ctx.restore();
  }
  ctx.globalAlpha = 1;
  ctx.textAlign = 'center';
  ctx.fillStyle = '#f7f1df';
  ctx.font = '800 46px Arial, sans-serif';
  ctx.fillText('Motion Scheduler', w / 2, 64);
  ctx.fillStyle = '#9fb6c9';
  ctx.font = '22px Arial, sans-serif';
  ctx.fillText('physics-inspired timing without losing frame determinism', w / 2, 104);
}

function render(t, c) {
  const { ctx, width: w, height: h, progress: p } = c;
  ctx.fillStyle = '#050914';
  ctx.fillRect(0, 0, w, h);
  const cx = w / 2, cy = h / 2 + 20;
  const points = [];
  for (let i = 0; i < 180; i++) {
    const a = i * 0.35 + t * 0.42;
    const b = i * 0.19 + t * 0.3;
    const r = 130 + (i % 30) * 5;
    const x3 = Math.cos(a) * r;
    const y3 = Math.sin(b) * r * 0.7;
    const z3 = Math.sin(a + b) * 220;
    const scale = 540 / (700 + z3);
    points.push([cx + x3 * scale, cy + y3 * scale, scale, z3, i]);
  }
  points.sort((a, b) => a[3] - b[3]);
  for (const pt of points) {
    const alpha = Math.max(0.12, Math.min(0.88, pt[2] * 1.2));
    ctx.globalAlpha = alpha * (0.35 + p * 0.65);
    ctx.fillStyle = pt[4] % 3 === 0 ? '#79d9ff' : pt[4] % 3 === 1 ? '#c7a6ff' : '#7bd88f';
    ctx.beginPath();
    ctx.arc(pt[0], pt[1], 3 + pt[2] * 9, 0, Math.PI * 2);
    ctx.fill();
  }
  ctx.globalAlpha = 1;
  ctx.textAlign = 'center';
  ctx.fillStyle = '#f7f1df';
  ctx.font = '800 46px Arial, sans-serif';
  ctx.fillText('Engine Adapter System', w / 2, 64);
  ctx.fillStyle = '#9fb6c9';
  ctx.font = '22px Arial, sans-serif';
  ctx.fillText('canvas today, Three.js and WebGL adapters as first-class routes', w / 2, 104);
}

function render(t, c) {
  const { ctx, width: w, height: h, progress: p } = c;
  ctx.fillStyle = '#06100d';
  ctx.fillRect(0, 0, w, h);
  ctx.globalCompositeOperation = 'lighter';
  for (let i = 0; i < 260; i++) {
    const col = i % 5;
    const baseX = (i * 83) % w;
    const baseY = (i * 47) % h;
    const flow = Math.sin(t * 0.7 + i * 0.13) * 90;
    const drift = Math.cos(t * 0.5 + i * 0.19) * 70;
    const x = (baseX + flow + w) % w;
    const y = (baseY + drift + h) % h;
    const r = 1.2 + (i % 6) * 0.9 + Math.sin(t * 3 + i) * 0.5;
    ctx.globalAlpha = 0.08 + Math.min(1, p * 1.8) * 0.42;
    ctx.fillStyle = col === 0 ? '#79d9ff' : col === 1 ? '#7bd88f' : col === 2 ? '#ff5c8a' : col === 3 ? '#f2aa4c' : '#c7a6ff';
    ctx.beginPath();
    ctx.arc(x, y, r, 0, Math.PI * 2);
    ctx.fill();
  }
  ctx.globalCompositeOperation = 'source-over';
  ctx.globalAlpha = 1;
  ctx.textAlign = 'center';
  ctx.fillStyle = '#f7f1df';
  ctx.font = '800 46px Arial, sans-serif';
  ctx.fillText('Particle Systems', w / 2, 64);
  ctx.fillStyle = '#9fb6c9';
  ctx.font = '22px Arial, sans-serif';
  ctx.fillText('large moving fields coordinated by the same segment clock', w / 2, 104);
}

function render(t, c) {
  const { ctx, width: w, height: h, progress: p } = c;
  ctx.fillStyle = '#100d08';
  ctx.fillRect(0, 0, w, h);
  const words = ['DEFINE', 'UI', 'VIDEO', 'WITH', 'TIME'];
  ctx.textAlign = 'center';
  ctx.textBaseline = 'middle';
  words.forEach((word, i) => {
    const y = 162 + i * 82;
    const reveal = Math.min(1, Math.max(0, p * 1.8 - i * 0.16));
    const x = w / 2 + Math.sin(t * 1.4 + i) * 18 * reveal;
    ctx.globalAlpha = 0.08;
    ctx.fillStyle = '#f7f1df';
    ctx.font = '900 78px Arial, sans-serif';
    ctx.fillText(word, w / 2, y + 16);
    ctx.globalAlpha = reveal;
    ctx.fillStyle = i % 2 ? '#f2aa4c' : '#f7f1df';
    ctx.font = '900 ' + (64 + reveal * 18) + 'px Arial, sans-serif';
    ctx.fillText(word, x, y);
    ctx.strokeStyle = i % 2 ? '#79d9ff' : '#ff5c8a';
    ctx.lineWidth = 2;
    ctx.strokeText(word, x, y);
  });
  ctx.globalAlpha = 1;
  ctx.fillStyle = '#9fb6c9';
  ctx.font = '22px Arial, sans-serif';
  ctx.fillText('typography is just another timed layer', w / 2, h - 54);
}

function render(t, c) {
  const { ctx, width: w, height: h, progress: p } = c;
  ctx.fillStyle = '#11080d';
  ctx.fillRect(0, 0, w, h);
  const labels = ['icons', 'lottie', 'fabric', 'svg', 'media', 'canvas', 'html', 'shader'];
  ctx.textAlign = 'center';
  ctx.textBaseline = 'middle';
  labels.forEach((label, i) => {
    const a = i / labels.length * Math.PI * 2 + t * 0.35;
    const r = 190 + Math.sin(t + i) * 26;
    const x = w / 2 + Math.cos(a) * r;
    const y = h / 2 + Math.sin(a) * r * 0.58;
    const reveal = Math.min(1, Math.max(0, p * 2 - i * 0.09));
    ctx.globalAlpha = reveal;
    ctx.fillStyle = i % 4 === 0 ? '#ff5c8a' : i % 4 === 1 ? '#79d9ff' : i % 4 === 2 ? '#7bd88f' : '#f2aa4c';
    ctx.beginPath();
    ctx.roundRect(x - 66, y - 32, 132, 64, 16);
    ctx.fill();
    ctx.fillStyle = '#08070b';
    ctx.font = '800 20px Arial, sans-serif';
    ctx.fillText(label, x, y + 1);
  });
  ctx.globalAlpha = 1;
  ctx.fillStyle = '#f7f1df';
  ctx.font = '800 48px Arial, sans-serif';
  ctx.fillText('Media Is Pluggable', w / 2, 78);
  ctx.fillStyle = '#9fb6c9';
  ctx.font = '22px Arial, sans-serif';
  ctx.fillText('each adapter can own its rendering model while runtime owns time', w / 2, h - 56);
}

export default {
  render(t, c) {
    const { ctx, width: w, height: h, progress: p } = c;
    ctx.fillStyle = '#05070b';
    ctx.fillRect(0, 0, w, h);
    const cx = w / 2;
    const cy = h / 2;
    ctx.save();
    ctx.translate(cx, cy);
    for (let i = 0; i < 48; i++) {
      const q = (i / 48 + p) % 1;
      const a = q * Math.PI * 2;
      const r = 110 + q * 260;
      ctx.globalAlpha = (1 - q) * 0.8;
      ctx.strokeStyle = i % 3 === 0 ? '#79d9ff' : i % 3 === 1 ? '#7bd88f' : '#f2aa4c';
      ctx.lineWidth = 4;
      ctx.beginPath();
      ctx.arc(Math.cos(a) * 18, Math.sin(a) * 10, r, a, a + Math.PI * 0.32);
      ctx.stroke();
    }
    ctx.globalAlpha = 1;
    ctx.fillStyle = '#f7f1df';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';
    ctx.font = '900 64px Arial, sans-serif';
    ctx.fillText('Render The Timeline', 0, -24);
    ctx.fillStyle = '#9fb6c9';
    ctx.font = '24px Arial, sans-serif';
    ctx.fillText('1800 frames, segment-aware, custom-code first', 0, 48);
    const barW = 620;
    ctx.strokeStyle = 'rgba(247,241,223,.22)';
    ctx.lineWidth = 2;
    ctx.strokeRect(-barW / 2, 110, barW, 18);
    ctx.fillStyle = '#79d9ff';
    ctx.fillRect(-barW / 2, 110, barW * p, 18);
    ctx.restore();
  }
}
